#include <bits/stdc++.h>
using namespace std;
int n,k,a[100005];
bool check(int mid){
	int sum=0;
	for(int i=1;i<=n;i++){
		sum+=a[i]/mid;
	}
	return sum>=k;
}
int main(){
	int l=1,r=0;
	long long sum=0;
	cin>>n>>k;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		r=max(r,a[i]);
		sum+=a[i];
	}
	if(sum<k){
		cout<<0;
		return 0;
	}
	while(l<r){
		int mid=(l+r+1)>>1;
		if(check(mid))l=mid;
		else r=mid-1;
	}
	cout<<l;
	return 0;
}
